#include <iostream>
#include <string>
#include <stdexcept> // Бібліотека стандартних винятків
using namespace std;

// === 1. ШАБЛОННИЙ КЛАС ===
// Дозволяємо класу бути "Гумовим" - підлаштовуватись під T
template <typename T>
class Storage {
private:
    T item;
public:
    Storage(T i) : item(i) {}
    T getItem() const { return item; }
};

// Функція з вбудованим АЛАРМОМ
double safeDivide(double a, double b) {
    if (b == 0) {
        // Ми "генеруємо" об'єкт винятку. 
        // Виконання ФУНКЦІЇ МИТТЄВО ПЕРЕРИВАЄТЬСЯ НА ЦЬОМУ РЯДКУ!
        throw runtime_error("Критична помилка: Ділення на НУЛЬ!");
    }
    return a / b;
}

int main() {
    // Демонстрація шаблонів (зверніть увагу на кутові дужки <>)
    Storage<int> intBox(42);
    Storage<string> strBox("Ключ від сейфу");

    cout << "В коробці: " << intBox.getItem() << endl;
    cout << "В іншій: " << strBox.getItem() << endl;

    // === 2. РОБОТА З ВИЩАТКАМИ (TRY - CATCH) ===
    cout << "
==== Запуск безпеки ====" << endl;

    try {
        cout << "Спроба 1: " << safeDivide(10, 2) << endl;

        cout << "Спроба 2: РИЗИК." << endl;
        // Тут буде генерований виняток! Увесь код після цього рядка всередині TRY - відкидається.
        double result = safeDivide(50, 0); 

        cout << "Це виведеться тільки якщо все добре: " << result << endl;
    } 
    catch (const exception& error) {
        // Ми успішно перехопили помилку! Програма НЕ падає.
        cout << "
[CATCH_BLOCK ВІДПРАЦЮВАВ] Ми запобігли крашу додатку!" << endl;
        // виводимо .what() - текст помилки
        cout << "Причина: " << error.what() << endl; 
    }

    cout << "
Гра продовжує стабільно працювати." << endl;

    return 0;
}
